INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES
(151, 'Ensino Fundamental: Anos Finais', 'Educação Física', '9º Ano', NULL, 'AE1', 'Praticar o futsal e o futebol de cegos, aplicando habilidades técnico-táticas básicas e respeitando as diferenças individuais.', NOW()),
(152, 'Ensino Fundamental: Anos Finais', 'Educação Física', '9º Ano', NULL, 'AE2', 'Praticar o basquete e o basquete em cadeira de rodas, aplicando habilidades técnico-táticas básicas, respeitando as diferenças individuais.', NOW()),
(153, 'Ensino Fundamental: Anos Finais', 'Educação Física', '9º Ano', NULL, 'AE3', 'Experimentar lutas do mundo, conhecendo técnicas e golpes dessas modalidades, respeitando o oponente.', NOW()),
(154, 'Ensino Fundamental: Anos Finais', 'Educação Física', '9º Ano', NULL, 'AE4', 'Vivenciar o MMA, a esgrima e a esgrima em cadeira de rodas, explorando técnicas e golpes, adaptando os materiais para a prática.', NOW()),
(155, 'Ensino Médio', 'Educação Física', '1ª Série', NULL, 'AE1', 'Vivenciar o futebol e suas variações, analisando os discursos midiáticos, valorizando a participação democrática, a equidade e o trabalho coletivo.', NOW()),
(156, 'Ensino Médio', 'Educação Física', '1ª Série', NULL, 'AE2', 'Experimentar o goalball, analisando preconceitos e estereótipos, para refletir em relação à inclusão, cooperação, respeito e ética.', NOW()),
(157, 'Ensino Médio', 'Educação Física', '1ª Série', NULL, 'AE3', 'Praticar o rugby e o futebol americano, compreendendo suas características e regras, analisando preconceitos presentes nas mídias.', NOW()),
(158, 'Ensino Médio', 'Educação Física', '1ª Série', NULL, 'AE4', 'Experimentar as danças do Brasil e do mundo, apreciando suas manifestações culturais, para ampliação da sensibilidade, imaginação e criatividade.', NOW()),
(159, 'Ensino Médio', 'Educação Física', '2ª Série', NULL, 'AE1', 'Praticar o tênis de mesa e o tênis de campo, identificando suas características, semelhanças e diferenças, para refletir sobre os estereótipos e as relações de poder presentes nessas práticas.', NOW()),
(160, 'Ensino Médio', 'Educação Física', '2ª Série', NULL, 'AE2', 'Vivenciar as danças do mundo, valorizando suas diversidades, para reflexão sobre as diferentes manifestações culturais.', NOW()),
(161, 'Ensino Médio', 'Educação Física', '3ª Série', NULL, 'AE1', 'Experimentar modalidades pouco praticadas no Brasil, explorando suas principais características, de modo a ampliar a cultura corporal de movimento.', NOW()),
(162, 'Ensino Médio', 'Educação Física', '3ª Série', NULL, 'AE2', 'Praticar esportes de quadra de areia, adaptando regras, espaços e materiais, a fim de ampliar a cultura corporal de movimento.', NOW()),
(163, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE1', 'Descrever paisagens a partir de seus elementos constitutivos, comparando as modificações dos lugares de vivência em diferentes tempos.', NOW()),
(164, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE2', 'Relacionar os processos de urbanização, industrialização e desenvolvimento da agropecuária às transformações observadas nas paisagens, reconhecendo as diferentes formas de organização do espaço e as mudanças na interação entre sociedade e natureza.', NOW()),
(165, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE3', 'Examinar as representações cartográficas, reconhecendo a importância da Cartografia como forma de linguagem para a interpretação do espaço, diferenciando os elementos de mapas com diferentes representações e escalas.', NOW()),
(166, 'Ensino Fundamental: Anos Finais', 'Geografia', '6º Ano', NULL, 'AE4', 'Classificar os principais tipos climáticos em diferentes lugares, com base em climogramas e mapas, explicando a diferença entre tempo e clima e a influência da circulação atmosférica.', NOW()),
(167, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE1', 'Comparar as regiões brasileiras em diferentes tempos, utilizando indicadores e representações (gráficos e mapas temáticos), relacionando desigualdades socioeconômicas e processos migratórios.', NOW()),
(168, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE2', 'Analisar como os fluxos econômicos e populacionais contribuem para a formação do território brasileiro e para o surgimento de tensões e conflitos, especialmente em São Paulo, com base em mapas temáticos.', NOW()),
(169, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE3', 'Analisar a distribuição territorial da população brasileira, relacionando os indicadores demográficos e considerando as diversidades étnico-raciais e culturais.', NOW()),
(170, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE4', 'Analisar o papel das redes de transporte e comunicação, explicando a evolução histórica e tecnológica dos fluxos materiais e imateriais em diferentes escalas.', NOW()),
(171, 'Ensino Fundamental: Anos Finais', 'Geografia', '7º Ano', NULL, 'AE5', 'Relacionar os processos de industrialização e inovação tecnológica às transformações socioeconômicas, políticas, culturais e ambientais no território brasileiro.', NOW()),
(172, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE1', 'Analisar a influência política, econômica, social e cultural da Nova Ordem Mundial estabelecida no pós-Segunda Guerra sobre os Estados Unidos, a América Latina, a África, com destaque para o Brasil.', NOW()),
(173, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE2', 'Analisar os conflitos e as tensões geopolíticas contemporâneas na América e na África, aplicando os conceitos de Estado, nação, território, governo e país.', NOW()),
(174, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE3', 'Analisar o papel dos organismos internacionais e regionais na mediação de conflitos em fronteiras latino-americanas, considerando as consequências políticas, econômicas e sociais para a população.', NOW()),
(175, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE4', 'Analisar padrões econômicos e geopolíticos mundiais, relacionando a produção e o intercâmbio dos Estados Unidos e dos BRICS com a atuação de organizações mundiais e blocos econômicos regionais.', NOW()),
(176, 'Ensino Fundamental: Anos Finais', 'Geografia', '8º Ano', NULL, 'AE5', 'Interpretar os efeitos do capital dos Estados Unidos e da China na reorganização das atividades econômicas globais, com destaque para o Brasil.', NOW()),
(177, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE1', 'Analisar o exercício da hegemonia europeia em diferentes tempos e lugares, usando representações cartográficas e gráficas para evidenciar desigualdades sociopolíticas e geopolíticas.', NOW()),
(178, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE2', 'Analisar fatos e situações da integração mundial econômica, política e cultural, comparando características e fenômenos da globalização com os da mundialização.', NOW()),
(179, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE3', 'Comparar regiões da Europa, Ásia e Oceania, a partir de mapas com diferentes projeções, para analisar as desigualdades sociopolíticas e geopolíticas decorrentes da hegemonia europeia.', NOW()),
(180, 'Ensino Fundamental: Anos Finais', 'Geografia', '9º Ano', NULL, 'AE4', 'Investigar a atuação das corporações internacionais e das organizações econômicas mundiais, discutindo suas influências socioeconômicas e culturais no cotidiano das populações em diferentes regiões do mundo.', NOW()),
(181, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE1', 'Analisar os impactos socioambientais das ações humanas coletivas e individuais, selecionando, incorporando e promovendo as que favoreçam a consciência e a ética socioambiental, consumo responsável e a mitigação das mudanças climáticas.', NOW()),
(182, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE2', 'Analisar as relações entre elementos naturais e ações humanas, reconhecendo os impactos e a importância da gestão sustentável da água, do relevo e dos biomas.', NOW()),
(183, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE3', 'Utilizar a linguagem cartográfica de forma crítica e reflexiva.', NOW()),
(184, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE4', 'Avaliar os efeitos da globalização, das transformações tecnológicas e dos blocos econômicos sobre o mundo do trabalho e as condições de vida das diferentes gerações.', NOW()),
(185, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE5', 'Avaliar os impactos socioeconômicos e socioambientais das cadeias produtivas ligadas à exploração de recursos naturais e à agropecuária.', NOW()),
(186, 'Ensino Médio', 'Geografia', '1ª Série', NULL, 'AE6', 'Comparar os impactos socioambientais de diferentes modelos socioeconômicos em escala global, analisando as iniciativas e políticas governamentais voltadas à promoção da sustentabilidade.', NOW()),
(187, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE1', 'Analisar como diferentes regiões se organizam, considerando aspectos culturais, econômicos, ambientais, políticos e sociais, com base em dados demográficos e econômicos.', NOW()),
(188, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE2', 'Analisar transformações econômicas, fluxos migratórios e processos de globalização, especialmente no Brasil, compreendendo suas causas, efeitos e implicações para a economia, a sociedade e as relações internacionais.', NOW()),
(189, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE3', 'Analisar indicadores socioeconômicos do Brasil, relacionando-os às leis trabalhistas e à atuação do país na economia mundial.', NOW()),
(190, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE4', 'Analisar os significados de Estado, nação, território, fronteiras e vazios (espacial, temporal e cultural), considerando a formação histórica, disputas territoriais e identidades culturais, incluindo o contexto brasileiro.', NOW()),
(191, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE5', 'Analisar os processos de urbanização no Brasil e no mundo, relacionando a formação de cidades, megacidades e territórios ao papel de diferentes agentes e aos impactos socioambientais e socioculturais envolvidos.', NOW()),
(192, 'Ensino Médio', 'Geografia', '2ª Série', NULL, 'AE6', 'Avaliar dados de desigualdade no campo e de modelos de produção, identificando políticas públicas e discutindo as características do agronegócio contemporâneo.', NOW()),
(193, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE1', 'Analisar as transformações e conservações de matéria e energia em sistemas biológicos, associando processos celulares e interações ecológicas à sustentabilidade ambiental.', NOW()),
(194, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE2', 'Explicar o aquecimento global, avaliando suas relações com as mudanças climáticas e os riscos ambientais provocados pelas ações humanas.', NOW()),
(195, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE3', 'Analisar os impactos socioambientais das fontes de energia renováveis e não renováveis a partir das matrizes mundial e brasileira.', NOW()),
(196, 'Ensino Médio', 'Biologia', '1ª Série', NULL, 'AE4', 'Reconhecer os impactos da poluição ambiental nos sistemas fisiológicos humanos, identificando ações e tecnologias voltadas à prevenção e promoção da saúde individual, coletiva e ambiental.', NOW()),
(197, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE1', 'Reconhecer os riscos e benefícios das radiações para a saúde humana.', NOW()),
(198, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE2', 'Relacionar a meiose à reprodução e a mitose ao crescimento, manutenção dos tecidos e origem de cânceres.', NOW()),
(199, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE3', 'Avaliar os efeitos de intervenções humanas nos ecossistemas, destacando seus impactos sobre a biodiversidade e propondo ações voltadas à sustentabilidade e prevenção de zoonoses.', NOW()),
(200, 'Ensino Médio', 'Biologia', '2ª Série', NULL, 'AE4', 'Avaliar os benefícios e riscos dos defensivos agrícolas, relacionando sua composição, toxicidade e exposição aos processos de bioacumulação e biomagnificação.', NOW());
